import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable, map } from 'rxjs';
import { NgxSpinnerService } from 'ngx-spinner';
import { IApiResponse } from '../shared/Interfaces/api-response';
import { CommonService } from './common.service';
import { environment } from '../../environments/environment';
import { AppRoutes } from '../shared/routes/appRoutes';
import { ApiUrls } from '../shared/routes/apiUrl';
import { SharedService } from './shared.service';

@Injectable({
  providedIn: 'root',
})
export class HttpService {
  appRoutes = AppRoutes;
  apiUrl = ApiUrls;

  constructor(
    private http: HttpClient,
    public _spinnerService: NgxSpinnerService,
    public _helperService: CommonService,
    public _sharedService: SharedService
  ) { }

  /**
   * Automatically chooses the correct API base
   */
  private resolveBaseUrl(apiBaseUrl?: string): string {
    switch (apiBaseUrl) {
      case 'admin':
        return environment.apiUrl2;
      case 'master':
        return environment.masterBaseUrl;
      case 'cm':
        return environment.cmBaseUrl;
      default:
        return environment.apiUrl;
    }
  }

  /**
   * GET request
   */
  get(api: string, apiBaseUrl?: string): Observable<IApiResponse> {
    const headers = new HttpHeaders({
      'Content-Type': 'application/json; charset=utf-8',
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Expose-Headers': '*',
      'Access-Control-Allow-Methods': 'GET',
      'Access-Control-Allow-Headers': '*',
    });

    const baseUrl = this.resolveBaseUrl(apiBaseUrl);

    return this.http.get<IApiResponse>(baseUrl + api, { headers }).pipe(
      map((response: any) =>
        typeof response === 'string' ? this.JsonParseData(response) : response
      )
    );
  }

  /**
   * POST request
   */
  post(api: string, data: any, apiBaseUrl?: string): Observable<IApiResponse> {
    const headers = new HttpHeaders({
      ...(!(data instanceof FormData) && {
        'Content-Type': 'application/json; charset=utf-8',
      }),
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Expose-Headers': '*',
      'Access-Control-Allow-Methods': 'POST',
      'Access-Control-Allow-Headers': '*',
    });

    const baseUrl = this.resolveBaseUrl(apiBaseUrl);
    const requestData = data instanceof FormData ? data : JSON.stringify(data);

    return this.http.post<IApiResponse>(baseUrl + api, requestData, { headers }).pipe(
      map((response) =>
        typeof response === 'string' ? this.JsonParseData(response) : response
      )
    );
  }

  public JsonParseData(data: any) {
    let result = data;
    try {
      result = JSON.parse(data);
    } catch (e) {
      console.log('[HttpService] JSON parse failed:', e);
    }
    return result;
  }
}
